prompt --application/shared_components/security/authorizations/admin_only
begin
wwv_flow_imp_shared.create_security_scheme(
 p_id=>wwv_flow_imp.id(3413105508405309025)
,p_name=>'Admin Only'
,p_static_id=>'admin-only'
,p_scheme_type=>'NATIVE_FUNCTION_BODY'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'plsql_function_body', wwv_flow_string.join(wwv_flow_t_varchar2(
    'DECLARE',
    '    v_role VARCHAR2(50);',
    '',
    'BEGIN',
    '',
    '    SELECT ROLE',
    '    INTO v_role',
    '    FROM USER_ROLES',
    '    WHERE USERNAME = UPPER(:APP_USER);',
    '',
    '    IF v_role = ''ADMIN'' THEN',
    '        RETURN TRUE;',
    '    ELSE',
    '        RETURN FALSE;',
    '    END IF;',
    '',
    'EXCEPTION',
    '    WHEN NO_DATA_FOUND THEN',
    '        RETURN FALSE;',
    '',
    'END;')))).to_clob
,p_version_scn=>'SH256:dNKDeRuSCxZtGA2u576-TmS5k7Tn4jjaDzADmCehciA'
,p_caching=>'NOCACHE'
,p_created_on=>wwv_flow_imp.dz('20260524125901Z')
,p_updated_on=>wwv_flow_imp.dz('20260524131248Z')
,p_created_by=>'DANISHNICHO7@GMAIL.COM'
,p_updated_by=>'DANISHNICHO7@GMAIL.COM'
);
end;
