,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    ''Total Books'' AS CARD_TITLE,',
'    COUNT(*) AS CARD_VALUE,',
'    ''fa-book'' AS CARD_ICON',
'FROM BOOKS',
'',
'UNION ALL',
'',
'SELECT',
'    ''Total Students'',',
'    COUNT(*),',
'    ''fa-users''',
'FROM STUDENTS',
'',
'UNION ALL',
'',
'SELECT',
'    ''Issued Books'',',
'    COUNT(*),',
'    ''fa-exchange''',
'FROM ISSUED_BOOKS',
'WHERE STATUS = ''Issued''',
'',
'UNION ALL',
'',
'SELECT',
'    ''Overdue Books'',',
'    COUNT(*),',
'    ''fa-warning''',
'FROM ISSUED_BOOKS',
'WHERE STATUS = ''Issued''',
'AND ISSUE_DATE <= SYSDATE - 15',
'UNION ALL',
'',
'SELECT',
'    ''Low Stock'',',
'    COUNT(*),',
'    ''fa-warning''',
'FROM BOOKS',
'WHERE AVAILABLE < 5'))
,p_lazy_loading=>false
