wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(3231848450617514304)
,p_plug_name=>'Overdue Books'
,p_static_id=>'overdue-books'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>10
,p_plug_grid_row_css_classes=>'#ROW_CLASS#'
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    I.ISSUE_ID,',
'    B.TITLE AS BOOK_NAME,',
'    S.NAME AS STUDENT_NAME,',
'    I.ISSUE_DATE,',
'',
'    TRUNC(SYSDATE - I.ISSUE_DATE) AS DAYS_ISSUED,',
'',
'    CASE',
'',
'        WHEN TRUNC(SYSDATE - I.ISSUE_DATE) <= 15',
'        THEN',
'            TRUNC(SYSDATE - I.ISSUE_DATE) * 5',
'',
'        WHEN TRUNC(SYSDATE - I.ISSUE_DATE) <= 30',
'        THEN',
'            (15 * 5)',
'            +',
'            ((TRUNC(SYSDATE - I.ISSUE_DATE) - 15) * 10)',
'',
'        ELSE',
'            (15 * 5)',
'            +',
'            (15 * 10)',
'            +',
'            ((TRUNC(SYSDATE - I.ISSUE_DATE) - 30) * 20)',
'',
'    END AS FINE_AMOUNT,',
'',
'    CASE',
'    WHEN TRUNC(SYSDATE - I.ISSUE_DATE) > 15',
'    THEN ''overdue-row''',
'END AS ROW_CLASS',
'',
'FROM ISSUED_BOOKS I',
'',
'JOIN BOOKS B',
'ON I.BOOK_ID = B.BOOK_ID',
'',
'JOIN STUDENTS S',
'ON I.STUDENT_ID = S.STUDENT_ID',
'',
'WHERE I.STATUS = ''Issued''',
'',
'ORDER BY I.ISSUE_DATE;'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
